@ARTICLE{10.1080/21623945.2025.2603605,
	author = {Chen C and Gao H and Tian Q and Cao J},
	title = {cAMP-PKA/EPAC signaling pathways: crucial regulators of lipid homeostasis.},
	journal = {Adipocyte},
	year = {2026},
	abstract = {Adipose omeostasishomoeostasis is maintained through the precise coordination of lipogenesis, lipolysis, and adipocyte differentiation, with microenvironmental components dynamically regulating lipid metabolism. Even though the classical cAMP-PKA pathway has been well-characterized for its function in lipid metabolism by phosphorylating transcription factors and lipolytic enzymes, little is known about how it collaborates with elements of the adipose tissue microenvironment, such as immune cells and the vascular endothelium, especially in pathological situations like obesity. EPAC, a newly discovered cAMP effector, has shown new signalingsignallingsignalling signalling pathways in the immune and cardiovascular systems by activating small G proteins. However, there are important understanding gaps regarding its roles in adipose metabolism, namely adipocyte development, microenvironmental interaction, and the pathophysiology of metabolic diseases. By bringing together disparate studies on PKA and EPAC, this review provides the first comprehensive synthesis of the cAMP-PKA/EPAC dual signaling signalling signallingcins signalling network, filling in knowledge gaps. The reciprocal regulation between this signaling signalling signalling signalling network and the adipose microenvironment establishes a novel 'signaling-microenvironment-systemic metabolism' framework for understanding metabolic disorders, including obesity, diabetes, and hepatic steatosis. Pharmacological modulation of the PKA/EPAC signalingsignalling signalling signalling pathways may therefore represent a viable therapeutic approach for restoring adipose tissue homeostasis homoeostasis.},
	doi = {10.1080/21623945.2025.2603605},
	pmid = {41503874 [Indexed for MEDLINE]},
	note = {PMC12785204}
}

@ARTICLE{10.1016/j.bbalip.2026.159715,
	author = {Tian L and Wang G and Zhang S and He Z and Zhao F and Chang M and Han W and Ye D and Li S and Yang G},
	title = {MiR-432 mediates bidirectional regulation in the determination of adipocyte fate.},
	journal = {Biochim Biophys Acta Mol Cell Biol Lipids},
	year = {2026},
	abstract = {Fat deposition represents a fundamental physiological process in mammalian energy metabolism, yet its molecular regulatory mechanisms remain incompletely understood. Adipocytes, the primary site of fat storage, develop through proliferation and differentiation of preadipocytes-a process controlled by multiple molecular regulators. MicroRNAs (miRNAs) act as crucial post-transcriptional regulators and play an essential role in mammalian adipogenesis. However, their specific functions in ovine tail fat deposition remain poorly characterized. This study aimed to systematically investigate the regulatory role of miR-432 in adipogenesis using sheep tail fat as a model system. Through establishing an in vitro preadipocyte culture model and implementing gain- and loss-of-function approaches via miRNA overexpression and antisense oligonucleotide inhibition, we demonstrated that elevated expression of miR-432 significantly enhanced preadipocyte proliferation, accompanied by upregulation of proliferation-related genes (Cyclin D, PCNA). However, it decreased lipid droplet accumulation and reduced the expression of differentiation markers (PPARγ, FABP4). Conversely, inhibition of miR-432 reduced cellular proliferation, downregulated key cell cycle genes (CCNB1, Cyclin B3), and enhanced adipogenic differentiation, as evidenced by increased lipid droplet formation and elevated expression of adipogenic genes (PPARγ, Adiponectin, FABP4). These findings demonstrate that miR-432 exerts a dual regulatory role in sheep tail adipogenesis by modulating both proliferative and differentiative processes in adipocytes. This research provides novel molecular insights into the regulatory mechanisms underlying fat deposition.},
	doi = {10.1016/j.bbalip.2026.159715},
	pmid = {41500444 [Indexed for MEDLINE]}
}

@ARTICLE{10.1126/sciadv.adz1385,
	author = {Hu R and Park J and Qian Y and Xiong S and Elsabbagh AH and Chhikara A and Fan H and Shi Z and Liu L and Li Y and Song Z and Mahmoud AM and Chen J and Baur JA and He Y and Layden BT and Zhou Z and Xu P and Ong SG and Wang Z and Jiang Y},
	title = {ERα activates NAMPT/IL-33 signaling to enhance beige thermogenesis and metabolic fitness.},
	abstract = {Beige adipocytes are inducible thermogenic fat cells that emerge within white adipose tissue (WAT) in response to thermogenic stimuli and confer metabolic benefits. However, obesity impairs the generation of beige adipocytes, and the underlying mechanisms remain poorly understood. Here, we show that obesity leads to a loss of adipose progenitor cells (APCs) in WAT, accompanied by reduced estrogen (E2) levels and nicotinamide phosphoribosyltransferase (NAMPT) expression. Supplementation with E2 or nicotinamide mononucleotide (NMN), an NAMPT-derived nicotinamide adenine dinucleotide (NAD+) precursor, restores beige adipogenesis in diet-induced obese mice. Mechanistically, estrogen receptor α (ERα) in APCs is required for beige fat formation by promoting Nampt transcription. We further demonstrate that NAMPT is both necessary and sufficient to drive APC proliferation and differentiation, with interleukin-33 (IL-33) acting downstream to mediate these effects. These findings uncover a critical ERα/NAMPT/IL-33 axis that preserves progenitor function and thermogenic capacity, offering a potential therapeutic strategy to combat obesity-induced beige fat failure and associated metabolic dysfunction.},
	doi = {10.1126/sciadv.adz1385},
	pmid = {41499496 [Indexed for MEDLINE]},
	note = {PMC12778055}
}

@ARTICLE{10.1016/j.ijbiomac.2025.150072,
	author = {Zhang Y and Chu M and Fan L and Bao P and Zhang L and Chai X and Yan P},
	title = {microRNA profiling unravels an abundant bta-miR-181a_R-1 that regulates yak adipogenic differentiation via the SIRT/FoxO1 pathway.},
	journal = {Int J Biol Macromol},
	year = {2026},
	abstract = {Yaks (Bos grunniens) have evolved distinctive metabolic adaptations that enable survival under the prolonged cold and nutrient-deficient conditions of the Qinghai-Tibetan Plateau. Adipose tissue plays a pivotal role in maintaining energy homeostasis. The proliferation and differentiation of preadipocytes are critical for the development of adipose tissue in bovines. MicroRNAs (miRNAs) are small regulatory molecules that participate in many cell biological processes, including development, differentiation, apoptosis, and metabolism. However, the expression profiles and functional roles of miRNAs in yak lipid metabolism remain largely unknown. To elucidate the molecular mechanisms underlying yak adipogenesis, we performed miRNA sequencing during yak preadipocyte differentiation and identified stage-specific expression profiles. Data analysis indicated that 252 (day 12 vs day 0), 167 (day 12 vs day 2), and 103 (day 2 vs day 0) miRNAs were differentially expressed in three stages, respectively. Further analysis identified 13 differentially co-expressed miRNAs across the three stages. Among the differentially co-expressed miRNAs, bta-miR-181a_R-1 was markedly upregulated during adipogenic differentiation. Functional assays revealed that bta-miR-181a_R-1 dramatically increased triglyceride accumulation and the expression of adipogenic marker genes (PPARγ, FABP4, and C/EBPα, P < 0.05), whereas it did not significantly affect preadipocyte proliferation. Mechanistically, bta-miR-181a_R-1 directly targeted sirtuin 1 (SIRT1), resulting in enhanced acetylation of forkhead box O1 (FoxO1) and promotion of lipid deposition via the FoxO signaling pathway. These findings reveal a novel miR-181a_R-1/SIRT1/FoxO1 regulatory axis that promotes yak adipocyte differentiation, providing new insights into miRNA-mediated adipogenesis in ruminants and a potential molecular basis for improving fat deposition in high-altitude livestock.},
	doi = {10.1016/j.ijbiomac.2025.150072},
	pmid = {41485665 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s12010-025-05504-w,
	author = {Eslami A and Ghayourvahdat A and Muhammad FA and Albadr RJ and Taher WM and Alwan M and Jawad MJ and Al-Nuaimi AMA and Azimizonuzi H},
	title = {An Overview of the Effects of Exercise on Viral Infection in Obesity: Recent Advances and Potential Mechanisms.},
	journal = {Appl Biochem Biotechnol},
	year = {2026},
	abstract = {The intersection of the global obesity epidemic with viral infection pandemics poses a significant public health problem. Obesity increases virus severity by inducing dyslipidemia-characterized by defective low-density lipoprotein (LDL) and high-density lipoprotein (HDL) particles-and establishes a condition of chronic, low-grade inflammation that undermines both innate and adaptive immunity. Moreover, cholesterol-enriched lipid rafts (LRs) in the plasma membrane, which are crucial for viral entry and replication, provide a molecular connection between dysregulated lipid metabolism and viral life cycles. Although exercise is acknowledged for its benefits to metabolic and immunological health, a thorough synthesis of its precise function in influencing the relationship between obesity and viral infection is lacking. This review examines the impact of exercise on lipid metabolism and adipose tissue function, as well as its subsequent effect on antiviral immunity. We discuss how exercise training may mitigate obesity-induced dyslipidemia, promote the health of white adipose tissue, reduce inflammation, and enhance both humoral and cellular immune responses. We also compile research about the direct impacts of exercise on different viral illnesses. In summary, obesity intensifies viral infections via dyslipidemia and compromised immunity. This study has identified a significant gap by demonstrating that regular exercise is a crucial non-pharmacological strategy for mitigating these hazards. We have outlined the comprehensive mechanism by which exercise enhances lipid metabolism and adipose tissue function, consequently strengthening antiviral immunity and disrupting the cycle of obesity-related susceptibility to severe viral diseases. Consequently, physical exercise should be regarded as a fundamental preventive measure.},
	doi = {10.1007/s12010-025-05504-w},
	pmid = {41485170 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.carbpol.2025.124809,
	author = {Lan W and Huang L and Teng J and Xia N and Song M and Li S and Li J},
	title = {Structural characterization and lipid-modulating effects of an inulin-type fructan from Bacillus amyloliquefaciens D189: Unraveling the microbiota-gut-liver axis.},
	journal = {Carbohydr Polym},
	year = {2026},
	abstract = {Our prior study isolated Bacillus amyloliquefaciens D189 from Liu-pao tea fermentation, finding its exopolysaccharide possessed lipid-lowering activity. This work addressed its unexplored EPS structure and in vivo anti-obesity mechanism. D189 produced a hybrid branched fructan-type EPS with a previously uncharacterized structure in the Bacillus genus, distinguishing it from other documented EPS. Its core comprises a β-(2→1)-linked fructofuranose backbone with α-(3,6)-linked glucopyranose branches and terminal β-fructofuranose residues via β-(2→3)/β-(2→1) linkages. In high-fat diet (HFD) mice, D189 EPS exhibited low-dose efficacy: 50 mg/kg significantly reduced LDL-C (surpassing positive controls), while 200 mg/kg yielded anti-obesity effects equivalent to 300 mg/kg inulin-type polysaccharides. Its metabolic benefits operated through: gut microbiota remodeling-enriching SCFA producers (Blautia for butyrate; Muribaculaceae for acetate/propionate) while suppressing pro-inflammatory Allobaculum/Lachnospiraceae. This was accompanied by elevations in butyrate (62.89%) and isovalerate (74.50%), which modulated folate/steroid pathways to reduce hepatic lipid deposition. Concurrently, the treatment decreased hyperlipidemia marker β-muricholic acid by inhibiting CDCA synthesis and enhancing its conversion to secondary bile acids (3β-HDCA/3β-UDCA), thereby lowering primary/secondary bile acid ratios. The treatment also restored hepatic FXR signaling (normalizing Cyp7a1/Cyp8b1) and ileal ASBT transporter expression. This study demonstrated that D189 EPS attenuated obesity by targeting the microbiota-gut-liver signaling pathway, suggesting its potential for metabolic disorder therapy.},
	doi = {10.1016/j.carbpol.2025.124809},
	pmid = {41475763 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.phrs.2025.108080,
	author = {Colognesi M and Gabbia D and Signor A and Sarill M and Centofanti L and Rinaldi A and Cascione L and Nunziata S and Banzato M and Mattarei A and Finzi G and Sonda S and Pendin D and Zanotto I and Comai S and Pasut G and Alajati A and Saponaro M and Bucciarelli L and Lunati ME and Guarato G and Goggi I and La Rosa S and Morano C and Paroni RC and Dei Cas M and Daniele G and Gentilucci M and Pappagallo M and Alimonti A and Manfredi PL and Folli F and De Martin S},
	title = {Low, non-psychedelic doses of psilocybin as a novel treatment for MASLD, obesity and type 2 diabetes via 5-HT2B receptor-dependent mechanisms.},
	journal = {Pharmacol Res},
	year = {2026},
	abstract = {The therapeutic potential of low, non-psychedelic doses of psilocybin, a fungal tryptamine alkaloid, was investigated in metabolic disorders including obesity, type 2 diabetes mellitus (T2DM), and liver steatosis. Mice fed a high-fat/high-fructose diet received chronic treatment with psilocybin (0.05 mg/kg) for 12 weeks. Body weight, liver histology, insulin sensitivity, and skeletal muscle function were assessed, and hepatic and muscle tissues underwent transcriptomic and lipidomic analyses. The role of three serotonin receptors (5-HT2A, 5-HT2B, and 5-HT2C) in psilocybin-induced metabolic effects was examined in human cell lines using pharmacological and CRISPR/Cas9-based genetic approaches. Low-dose psilocybin reduced body-weight gain, liver steatosis, hyperglycaemia, and insulin resistance without eliciting central nervous system effects. Multi-omics analyses revealed near-complete normalization of disrupted hepatic lipid and carbohydrate metabolism pathways. Psilocybin also improved muscle strength and function, potentially through restoration of leptin sensitivity. Mechanistic studies demonstrated that these metabolic benefits were independent of the canonical psychedelic target 5-HT2A and instead resulted from antagonism of the serotonin 5-HT2B receptor in the liver. Overall, chronic low-dose psilocybin exerts broad metabolic benefits via a hepatic 5-HT2B-dependent mechanism, distinct from its psychedelic effects, supporting its potential as a novel therapeutic strategy for liver steatosis, obesity, T2DM, and sarcopenia.},
	doi = {10.1016/j.phrs.2025.108080},
	pmid = {41475502 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jnutbio.2025.110245,
	author = {Kwon H and Seo DS and Ahmad Y and Park S and Yoo J and Lee J and Bae HJ and Jang Y},
	title = {Complementary mechanisms of high-carbohydrate diets and ketogenic diets restore adult hippocampal neurogenesis and cognitive function in high-fat diet induced obesity in mice.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {High-fat diet (HFD)-induced obesity impairs cognition and hippocampal neurogenesis, linked to reduced metabolic flexibility between mitochondrial fatty acid β-oxidation (FAO) and cytosolic de novo lipogenesis (DNL). It is not fully understood if switching to a high-carbohydrate diet (HCD) or a ketogenic diet (KD) could reverse these HFD-induced deficits, or if they do so through different mechanisms. Male C57BL/6J mice received HFD for 8 weeks to induce obesity. Mice were then either maintained on the HFD or switched to an HCD or KD for an additional 8 weeks. We evaluated systemic metabolism (body weight, serum biochemistry), tissue-specific metabolic remodeling (RNA-seq, histology, RT-qPCR, Western blot) and cognitive function (Y-maze test, novel object recognition test). Both HCD and KD interventions reversed HFD‐induced systemic abnormalities, including reducing ALT/AST, cholesterol, and LDL, and attenuating hepatic steatosis and adipocyte hypertrophy. Metabolically, KD markedly increased β‐hydroxybutyrate, whereas HCD showed a distinct triglyceride profile. Both diets improved hippocampus-dependent working and recognition memory. Hippocampal RNA‐seq revealed diet-specific mechanisms. HCD enriched anabolic processes, including upregulation of glucose transporters (Glut 1, 2, 3, 4) and DNL pathway (ACLY-ACC-FASN-SCD1). Conversely, KD enriched AMPK signaling, increasing monocarboxylate transporters (Mct 1, 2, 4) for ketone uptake and activating the neurotrophic AMPK-ERK-CREB-BDNF pathway. In conclusion, post-HFD switching to HCD or KD restores hippocampal structure and cognition via complementary mechanisms. HCD drives a substrate-centric, lipogenic program supporting proliferation, whereas KD engages a signaling-centric, neurotrophic program enhancing plasticity. Metabolic flexibility is a promising target for obesity-associated cognitive decline.},
	doi = {10.1016/j.jnutbio.2025.110245},
	pmid = {41475465 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.psj.2025.106334,
	author = {Li M and Liu M and Yang Y and Ruan J and Gu Z and Ge C and Cao W},
	title = {Transcriptomic and metabolomic insights into lipid metabolism genes underlying meat quality differences between yellow-feathered and white-feathered broilers in China.},
	abstract = {One important element impacting meat quality is fat metabolism, which mainly affects meat features through intramuscular fat deposition. Chinese native yellow-feathered broilers and white-feathered broilers differ significantly in intramuscular fat concentration. This study used transcriptomic and metabolomic sequencing technologies to identify a total of 173 differentially expressed genes and 259 differential metabolites in the pectoral muscles of Chahua Chicken No. 2 and Cobb broiler in order to explore the genetic mechanisms by which lipid metabolism influences meat quality in Chinese indigenous yellow-feathered and white-feathered broilers. These included differentially expressed genes like FABP1, LPL, ELOVL7, SLC27A1, MOGAT1, and ULK2, which were enriched in pathways relevant to lipid metabolism and showed strong associations with γ-linolenic acid and palmitaldehyde, two distinct metabolites. In order to develop local chicken germplasm resources and breed superior indigenous chicken varieties, these candidate genes could serve as the genetic foundation for the variations in meat quality and lipid metabolism between Chinese native yellow-feathered and white-feathered broilers.},
	doi = {10.1016/j.psj.2025.106334},
	pmid = {41475172 [Indexed for MEDLINE]},
	note = {PMC12804028}
}

@ARTICLE{10.1016/j.ygeno.2025.111182,
	author = {Fu X and Zhao L and Tian H and Zhang D and Zhang Y and Zhao Y and Cheng J and Li X and Xu Q and Xu D and Yang X and Ma Z and Wu W and Li F and Wang W and Zhang X},
	title = {Genome-wide association and transcriptome studies identify candidate genes regulating perirenal fat deposition in sheep.},
	journal = {Genomics},
	year = {2026},
	abstract = {Perirenal fat deposition significantly impacts sheep carcass quality and economic efficiency. To elucidate the underlying genetic regulation, we performed a genome-wide association study (GWAS) on 556 Hu sheep and a comparative transcriptome analysis on 24 Hu sheep (12 with high- and 12 with low-perirenal fat deposition), all with accurate phenotypic records. Furthermore, hub genes and tissue-specific genes (TSGs) were discerned through weighted gene co-expression network analysis (WGCNA) and by leveraging RNA-Seq data from 12 tissues, respectively. qRT-PCR is used to validate the accuracy of RNA-Seq data. GWAS identified significant SNPs near genes including SETD4, TIMP2, SOCS3, and DNAH17. Comparative transcriptome analysis of HPF and LPF groups identified 2072 differentially expressed genes (DEGs), which were significantly associated with lipid storage (LPL), fatty acid homeostasis (APOE, GOT1), and biosynthesis (ACACA). A total of 2333 differential alternative splicing events were identified in 1169 genes, with skipped exons (SE, 30.65 %) being the most common. GO analysis of these SEs showed links to RNA splicing and lipid metabolism, with genes like BSCL2, DGAT1, PLIN5, and PNPLA2 involved in lipid droplet organization and triglyceride storage. WGCNA revealed key modules that were positively and negatively correlated with perirenal fat deposition, emphasizing hub genes (SAR1B, THRSP, ACSS2, KIF5B) associated with lipid droplet organization and metabolism. The integrated analysis of GWAS and RNA-seq identified TIMP2, SOCS3, and DNAH17 as potential key genes involved in regulating perirenal fat deposition in sheep. An association analysis of 372 Hu sheep populations identified significant links (P < 0.05) between perirenal fat deposition traits and mutations in the TIMP2 (g.9759169 G > A) and DNAH17 (g.9494469C > T) genes. Crucially, tissue-specific gene analysis across 12 tissues identified 448 perirenal fat TSGs, of which 75 were also differentially expressed genes (e.g., LPL, THRSP, LEP, ADRB3). In conclusion, our multi-omics study identified key genes influencing perirenal fat deposition in sheep. Notably, mutations in TIMP2 and DNAH17 could serve as candidate markers for enhancing carcass quality through marker-assisted selection.},
	doi = {10.1016/j.ygeno.2025.111182},
	pmid = {41453584 [Indexed for MEDLINE]}
}
